/* ── GLOBE ── canvas-texture approach for smooth country shapes ── */
(function() {
  const canvas = document.getElementById('globe-canvas');
  const renderer = new THREE.WebGLRenderer({canvas, antialias:true, alpha:true});
  renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
  const scene = new THREE.Scene();
  const camera = new THREE.PerspectiveCamera(42, 1, 0.1, 100);
  camera.position.z = 2.75;
  function resize() {
    const w = canvas.parentElement.clientWidth, h = canvas.parentElement.clientHeight;
    renderer.setSize(w, h); camera.aspect = w/h; camera.updateProjectionMatrix();
  }
  resize(); window.addEventListener('resize', resize);
  scene.add(new THREE.AmbientLight(0xffffff, 0.7));
  const sun = new THREE.DirectionalLight(0xffffff, 0.8); sun.position.set(4,3,5); scene.add(sun);
  const rim = new THREE.DirectionalLight(0xa8e04a, 0.18); rim.position.set(-5,-2,-3); scene.add(rim);

  const G = new THREE.Group(); scene.add(G);
  const R = 1.0;

  // Complete and pending country IDs
  const cSet = new Set([24,204,72,108,120,148,178,818,226,231,266,270,288,404,430,434,466,508,516,566,646,686,694,706,728,729,834,768,788,800,894,116,496]);
  const pSet = new Set([12,854,132,140,174,180,384,262,232,748,324,624,426,450,454,478,480,504,562,678,686,710,716,710,418,104,764,704]);

  // Draw world map onto an offscreen canvas as equirectangular texture
  function buildTexture(world) {
    const TW = 2048, TH = 1024;
    const tc = document.createElement('canvas');
    tc.width = TW; tc.height = TH;
    const ctx = tc.getContext('2d');

    // Ocean background
    ctx.fillStyle = '#0e3d4a';
    ctx.fillRect(0, 0, TW, TH);

    // D3 equirectangular projection mapped to texture canvas
    const proj = d3.geoEquirectangular()
      .scale(TH / Math.PI)
      .translate([TW/2, TH/2]);
    const path = d3.geoPath(proj, ctx);

    // Draw each country
    topojson.feature(world, world.objects.countries).features.forEach(f => {
      const id = +f.id;
      ctx.beginPath();
      path(f);
      ctx.fillStyle = cSet.has(id) ? '#3d7a1a' : pSet.has(id) ? '#9b2020' : '#1a5a6a';
      ctx.fill();
      ctx.strokeStyle = 'rgba(255,255,255,0.18)';
      ctx.lineWidth = 0.5;
      ctx.stroke();
    });

    // Graticule lines
    const grat = d3.geoGraticule()();
    ctx.beginPath();
    path(grat);
    ctx.strokeStyle = 'rgba(168,224,74,0.06)';
    ctx.lineWidth = 0.5;
    ctx.stroke();

    const tex = new THREE.CanvasTexture(tc);
    return tex;
  }

  // Ocean sphere (visible while texture loads)
  const oceanMat = new THREE.MeshPhongMaterial({color:0x0e3d4a, emissive:0x061e25, shininess:40});
  const globe = new THREE.Mesh(new THREE.SphereGeometry(R, 64, 64), oceanMat);
  G.add(globe);

  // Atmosphere glow
  G.add(new THREE.Mesh(
    new THREE.SphereGeometry(R*1.02, 64, 64),
    new THREE.MeshPhongMaterial({color:0x4aaccc, transparent:true, opacity:0.04, side:THREE.FrontSide})
  ));

  d3.json('https://cdn.jsdelivr.net/npm/world-atlas@2/countries-110m.json').then(world => {
    const tex = buildTexture(world);
    globe.material = new THREE.MeshPhongMaterial({map: tex, specular:0x111111, shininess:20});
    globe.material.needsUpdate = true;
  });

  let drag=false, px=0, py=0, rotY=0.3, rotX=0.15, vy=0, vx=0;
  canvas.addEventListener('mousedown', e=>{drag=true; px=e.clientX; py=e.clientY; vy=0; vx=0;});
  window.addEventListener('mouseup', ()=>drag=false);
  window.addEventListener('mousemove', e=>{if(!drag)return; vy=(e.clientX-px)*0.005; vx=(e.clientY-py)*0.003; px=e.clientX; py=e.clientY;});
  canvas.addEventListener('touchstart', e=>{drag=true; px=e.touches[0].clientX; py=e.touches[0].clientY; vy=0; vx=0;},{passive:true});
  window.addEventListener('touchend', ()=>drag=false);
  window.addEventListener('touchmove', e=>{if(!drag)return; vy=(e.touches[0].clientX-px)*0.004; vx=(e.touches[0].clientY-py)*0.003; px=e.touches[0].clientX; py=e.touches[0].clientY;},{passive:true});
  (function animate(){
    requestAnimationFrame(animate);
    if(!drag){vy*=0.96; vx*=0.94;}
    rotY += drag ? vy : 0.0025+vy;
    rotX += vx;
    rotX = Math.max(-1.1, Math.min(1.1, rotX));
    G.rotation.y = rotY; G.rotation.x = rotX;
    renderer.render(scene, camera);
  })();
})();

/* ── MAP DATA ── */
const africaComplete=new Set(['Angola','Benin','Botswana','Burundi','Cameroon','Chad','Congo-Brazzaville','Egypt','Equatorial Guinea','Ethiopia','Gabon','Gambia','Ghana','Kenya','Liberia','Libya','Mali','Mozambique','Namibia','Nigeria','Rwanda','Senegal','Sierra Leone','Somalia','South Sudan','Sudan','Tanzania','Togo','Tunisia','Uganda','Zambia']);
const africaPending=new Set(['Algeria','Burkina Faso','Cabo Verde','Central African Republic','Comoros',"Côte d'Ivoire",'Djibouti','Eritrea','Eswatini','Guinea','Guinea-Bissau','Lesotho','Madagascar','Malawi','Mauritania','Mauritius','Morocco','Niger',"São Tomé and Príncipe",'Seychelles','South Africa','DR Congo','Zimbabwe']);
const seaComplete=new Set(['Cambodia','Mongolia','Vietnam']);
const seaPending=new Set(['Laos','Myanmar','Thailand']);
const africaIslands=[
  {name:'Cabo Verde',lon:-23.0,lat:15.1,dx:14,dy:-12,anchor:'start'},
  {name:"São Tomé & Príncipe",lon:6.6,lat:0.2,dx:-14,dy:16,anchor:'end'},
  {name:'Comoros',lon:43.7,lat:-11.7,dx:14,dy:-12,anchor:'start'},
  {name:'Mauritius',lon:57.6,lat:-20.2,dx:14,dy:-12,anchor:'start'},
  {name:'Seychelles',lon:55.5,lat:-4.6,dx:14,dy:-12,anchor:'start'},
];
function getAN(id){const m={12:'Algeria',24:'Angola',204:'Benin',72:'Botswana',854:'Burkina Faso',108:'Burundi',132:'Cabo Verde',120:'Cameroon',140:'Central African Republic',148:'Chad',174:'Comoros',178:'Congo-Brazzaville',180:'DR Congo',384:"Côte d'Ivoire",262:'Djibouti',818:'Egypt',226:'Equatorial Guinea',232:'Eritrea',231:'Ethiopia',266:'Gabon',270:'Gambia',288:'Ghana',324:'Guinea',624:'Guinea-Bissau',404:'Kenya',426:'Lesotho',430:'Liberia',434:'Libya',450:'Madagascar',454:'Malawi',466:'Mali',478:'Mauritania',480:'Mauritius',504:'Morocco',508:'Mozambique',516:'Namibia',562:'Niger',566:'Nigeria',646:'Rwanda',678:"São Tomé and Príncipe",686:'Senegal',694:'Sierra Leone',706:'Somalia',710:'South Africa',729:'Sudan',728:'South Sudan',716:'Zimbabwe',768:'Togo',788:'Tunisia',800:'Uganda',834:'Tanzania',894:'Zambia',732:'Western Sahara'};return m[id]||null;}
function getSN(id){return {116:'Cambodia',418:'Laos',104:'Myanmar',764:'Thailand',704:'Vietnam',496:'Mongolia'}[id]||null;}

const CC='#5a9e2f',CP='#c0392b',CO='#1e5560',CS='rgba(255,255,255,0.14)',CL='rgba(255,255,255,0.28)';
const tt=document.getElementById('map-tt');
function tip(e,n,s){
  const sc=s==='Complete'?CC:CP;
  const isRich = s && s.includes('<');
  if(isRich){
    tt.innerHTML=`<strong style="font-size:13px;color:#A8E04A;">${n}</strong>${s}`;
    tt.style.whiteSpace='normal';
  } else {
    tt.innerHTML=`<strong>${n}</strong><span style="color:${sc};margin-left:10px;">${s}</span>`;
    tt.style.whiteSpace='nowrap';
  }
  tt.style.opacity='1';
  tt.style.left=(e.clientX+16)+'px';
  tt.style.top=(e.clientY-12)+'px';
}
function untip(){tt.style.opacity='0';}

const extA={
  'Gambia':[58,212],'Guinea-Bissau':[38,242],'Sierra Leone':[38,270],'Liberia':[44,292],
  'Togo':[472,270],'Benin':[484,254],'Rwanda':[482,304],'Burundi':[490,318],
  'Djibouti':[486,216],'Eritrea':[492,197],'Lesotho':[476,432],'Eswatini':[486,414],
  'Equatorial Guinea':[60,314]
};

let worldData=null;

function buildAfricaSVG(container, W, H) {
  const svg=d3.select(container).append('svg')
    .attr('width', W)
    .attr('height', H)
    .attr('viewBox',`0 0 ${W} ${H}`)
    .attr('preserveAspectRatio','xMidYMid meet')
    .style('display','block');
  const proj=d3.geoMercator().center([22,0]).scale(W*0.44).translate([W/2+10,H/2+20]);
  const path=d3.geoPath(proj);
  const africa=topojson.feature(worldData,worldData.objects.countries).features.filter(d=>!!getAN(+d.id));
  svg.selectAll('path').data(africa).join('path').attr('d',path).attr('stroke',CS).attr('stroke-width',0.5)
    .attr('fill',d=>{const n=getAN(+d.id);return africaComplete.has(n)?CC:africaPending.has(n)?CP:CO;})
    .style('cursor','pointer')
    .on('mousemove',(e,d)=>{const n=getAN(+d.id);const dn=n==='DR Congo'?'DR Congo (Kinshasa)':n==='Congo-Brazzaville'?'Congo (Brazzaville)':n;tip(e,dn,africaComplete.has(n)?'Complete':'Pending');})
    .on('mouseleave',untip);
  const lg=svg.append('g'),ll=svg.append('g');
  africa.forEach(d=>{
    const n=getAN(+d.id);if(!n)return;
    const c=path.centroid(d);if(!c||isNaN(c[0]))return;
    const area=path.area(d);const ext=extA[n];
    const disp=n.replace('Congo-Brazzaville','Congo-B').replace('DR Congo','DR Congo').replace('Central African Republic','Cent. African Rep.').replace('Western Sahara','W. Sahara').replace('Equatorial Guinea','Eq. Guinea');
    if(ext){const[lx,ly]=ext;lg.append('line').attr('x1',c[0]).attr('y1',c[1]).attr('x2',lx<W/2?lx+5:lx-5).attr('y2',ly).attr('stroke',CL).attr('stroke-width',0.7).attr('stroke-dasharray','2,2');ll.append('text').attr('x',lx<W/2?lx-2:lx+2).attr('y',ly+3).attr('text-anchor',lx<W/2?'end':'start').attr('font-size',W>600?'8px':'6px').attr('font-family','DM Sans,sans-serif').attr('fill','#c8d8dc').attr('font-weight','500').text(disp);}
    else{if(area<70*(W/520)**2)return;const fs=area>3000*(W/520)**2?W>600?9:7:area>800*(W/520)**2?W>600?8:6.5:W>600?7:5.5;const words=disp.split(' ');if(words.length>=3&&area>1200*(W/520)**2){const mid=Math.ceil(words.length/2);[[words.slice(0,mid).join(' '),-4],[words.slice(mid).join(' '),8]].forEach(([t,dy])=>{ll.append('text').attr('x',c[0]).attr('y',c[1]+dy).attr('text-anchor','middle').attr('font-size',fs+'px').attr('font-family','DM Sans,sans-serif').attr('fill','#fff').attr('font-weight','500').attr('paint-order','stroke').attr('stroke','rgba(0,0,0,0.65)').attr('stroke-width','2px').text(t);})}else{ll.append('text').attr('x',c[0]).attr('y',c[1]+2).attr('text-anchor','middle').attr('font-size',fs+'px').attr('font-family','DM Sans,sans-serif').attr('fill','#fff').attr('font-weight','500').attr('paint-order','stroke').attr('stroke','rgba(0,0,0,0.65)').attr('stroke-width','2px').text(disp);}}
  });
  const ig=svg.append('g');
  africaIslands.forEach(isl=>{
    const[px,py]=proj([isl.lon,isl.lat]);const col=CP;const lx=px+isl.dx*(W/520)*2,ly=py+isl.dy*(H/620)*1.4;
    ig.append('circle').attr('cx',px).attr('cy',py).attr('r',W>600?5:3.5).attr('fill',col).attr('stroke','rgba(255,255,255,0.35)').attr('stroke-width',0.8).style('cursor','pointer').on('mousemove',e=>tip(e,isl.name,'Pending')).on('mouseleave',untip);
    ig.append('line').attr('x1',px).attr('y1',py).attr('x2',lx).attr('y2',ly).attr('stroke',CL).attr('stroke-width',0.6).attr('stroke-dasharray','2,2');
    ig.append('text').attr('x',lx+(isl.anchor==='start'?2:-2)).attr('y',ly+3).attr('text-anchor',isl.anchor).attr('font-size',W>600?'8px':'6px').attr('font-family','DM Sans,sans-serif').attr('fill','#c8d8dc').attr('font-weight','500').text(isl.name);
  });
  return svg;
}

function buildSEASVG(container, W, H) {
  const svg=d3.select(container).append('svg')
    .attr('width', W)
    .attr('height', H)
    .attr('viewBox',`0 0 ${W} ${H}`)
    .attr('preserveAspectRatio','xMidYMid meet')
    .style('display','block');

  // Background
  svg.append('rect').attr('width',W).attr('height',H).attr('fill','#0d3b3e');

  // SE Asia projection — shift down a bit to leave room for Mongolia inset
  const seaCountries=['Cambodia','Laos','Myanmar','Thailand','Vietnam'];
  const proj=d3.geoMercator().center([103,17]).scale(W*0.85).translate([W/2, H*0.62]);
  const path=d3.geoPath(proj);
  const sea=topojson.feature(worldData,worldData.objects.countries).features.filter(d=>{
    const n=getSN(+d.id);
    return n && seaCountries.includes(n); // exclude Mongolia from main map
  });
  svg.selectAll('path.sea').data(sea).join('path').attr('class','sea').attr('d',path)
    .attr('stroke',CS).attr('stroke-width',0.5)
    .attr('fill',d=>{const n=getSN(+d.id);return seaComplete.has(n)?CC:seaPending.has(n)?CP:CO;})
    .style('cursor','pointer')
    .on('mousemove',(e,d)=>{const n=getSN(+d.id);tip(e,n,seaComplete.has(n)?'Complete':'Pending');})
    .on('mouseleave',untip);

  // Labels for SE Asia countries
  const ll=svg.append('g');
  sea.forEach(d=>{
    const n=getSN(+d.id);if(!n)return;
    const c=path.centroid(d);if(!c||isNaN(c[0]))return;
    const area=path.area(d);if(area<80)return;
    const fs=area>8000?W>600?12:9:area>2000?W>600?11:8:W>600?9:7;
    ll.append('text').attr('x',c[0]).attr('y',c[1]+2).attr('text-anchor','middle')
      .attr('font-size',fs+'px').attr('font-family','DM Sans,sans-serif')
      .attr('fill','#fff').attr('font-weight','500')
      .attr('paint-order','stroke').attr('stroke','rgba(0,0,0,0.65)').attr('stroke-width','2.5px').text(n);
  });

  // Mongolia inset — top right area of the SVG
  const mW = W * 0.38;
  const mH = H * 0.18;
  const mX = W * 0.58;
  const mY = H * 0.04;

  // Inset background + border
  svg.append('rect').attr('x',mX-8).attr('y',mY-8).attr('width',mW+16).attr('height',mH+16)
    .attr('rx',8).attr('fill','rgba(13,59,62,0.85)').attr('stroke','rgba(168,224,74,0.2)').attr('stroke-width',1);

  // Mongolia projection fitted to inset box
  const mongFeature = topojson.feature(worldData,worldData.objects.countries).features.find(d=>+d.id===496);
  if(mongFeature){
    const mongProj = d3.geoMercator().fitExtent([[mX,mY],[mX+mW,mY+mH]], mongFeature);
    const mongPath = d3.geoPath(mongProj);
    svg.append('path')
      .datum(mongFeature)
      .attr('d', mongPath)
      .attr('fill', CC)
      .attr('stroke', CS)
      .attr('stroke-width', 0.5)
      .style('cursor','pointer')
      .on('mousemove', e=>tip(e,'Mongolia','Complete'))
      .on('mouseleave', untip);

    // Mongolia label
    const mc = mongPath.centroid(mongFeature);
    svg.append('text').attr('x',mc[0]).attr('y',mc[1]+2).attr('text-anchor','middle')
      .attr('font-size',W>600?'11px':'8px').attr('font-family','DM Sans,sans-serif')
      .attr('fill','#fff').attr('font-weight','500')
      .attr('paint-order','stroke').attr('stroke','rgba(0,0,0,0.65)').attr('stroke-width','2px')
      .text('Mongolia');
  }

  // Inset label
  svg.append('text').attr('x',mX-4).attr('y',mY-14).attr('font-size','9px')
    .attr('font-family','DM Sans,sans-serif').attr('fill','rgba(255,255,255,0.35)')
    .attr('font-weight','600').attr('letter-spacing','0.08em').text('INSET');

  return svg;
}

/* ── MODAL ── */
function openModal(type) {
  const modal=document.getElementById('map-modal');
  const body=document.getElementById('modal-body');
  body.innerHTML='';
  modal.classList.add('open');
  document.body.style.overflow='hidden';
  if(type==='africa'){
    document.getElementById('modal-title').textContent='Africa Survey Map';
    document.getElementById('modal-meta').textContent='31 of 55 countries responded · 56.4% response rate';
  }else{
    document.getElementById('modal-title').textContent='Southeast Asia Survey Map';
    document.getElementById('modal-meta').textContent='3 of 6 countries responded · 50% response rate';
  }
  requestAnimationFrame(()=>requestAnimationFrame(()=>{
    const W = body.clientWidth  || window.innerWidth;
    const H = body.clientHeight || (window.innerHeight - 115);

    // Build SVG at screen size
    const svgSel = type==='africa'
      ? buildAfricaSVG(body, W, H)
      : buildSEASVG(body, W, H);

    // Size the SVG to fill the container exactly
    svgSel.style('width', W+'px').style('height', H+'px').style('position','absolute').style('top','0').style('left','0');

    // Apply D3 zoom directly to the SVG, transforming an inner <g>
    // Wrap all children in a zoom group
    const svgEl = svgSel.node();
    const zoomG = document.createElementNS('http://www.w3.org/2000/svg','g');
    zoomG.setAttribute('class','zoom-g');
    while(svgEl.firstChild) zoomG.appendChild(svgEl.firstChild);
    svgEl.appendChild(zoomG);

    const zoom = d3.zoom()
      .scaleExtent([0.8, 8])
      .on('start', ()=>body.classList.add('panning'))
      .on('end',   ()=>body.classList.remove('panning'))
      .on('zoom', (event)=>{
        d3.select(zoomG).attr('transform', event.transform);
      });

    svgSel.call(zoom);

    // Start at a scale that fits everything, centered
    const initScale = 0.85;
    const tx = W*(1-initScale)/2;
    const ty = H*(1-initScale)/2;
    svgSel.call(zoom.transform, d3.zoomIdentity.translate(tx,ty).scale(initScale));
  }));
}
function closeModal(){
  document.getElementById('map-modal').classList.remove('open');
  document.body.style.overflow='';
  untip();
}
document.getElementById('map-modal').addEventListener('keydown',e=>{if(e.key==='Escape')closeModal();});
document.addEventListener('keydown',e=>{if(e.key==='Escape')closeModal();});

