function getCountryTip(name) {
  const d = countryEPData[name];
  if (!d) return '<span style="color:rgba(255,255,255,0.45);font-size:11px;">Data Not Yet Available</span>';
  const ablRow = d.ablatingEPs > 0
    ? `${d.ablatingEPs} EP${d.ablatingEPs>1?'s':''} <span style="color:#FF4C4C;font-size:11px;">(${d.ablationRatio})</span>`
    : `<span style="color:#e67e22;">None</span>`;
  const devRow = d.deviceEPs > 0
    ? `${d.deviceEPs} physician${d.deviceEPs>1?'s':''} <span style="color:#FF4C4C;font-size:11px;">(${d.deviceRatio})</span>`
    : `<span style="color:#e67e22;">None</span>`;
  const visitColor = d.visitingEP==='Yes' ? '#A8E04A' : d.visitingEP==='No' ? '#e67e22' : 'rgba(255,255,255,0.45)';
  return `<div style="border-top:1px solid rgba(168,224,74,0.2);margin-top:4px;padding-top:6px;display:grid;grid-template-columns:auto auto;gap:2px 12px;font-size:12px;">
    <span style="color:#fff;font-weight:bold;">Population</span><span>${d.pop}M</span>
    <span style="color:#fff;font-weight:bold;">Ablating EPs</span><span>${ablRow}</span>
    <span style="color:#fff;font-weight:bold;">Device physicians</span><span>${devRow}</span>
    <span style="color:#fff;font-weight:bold;">Device centers</span><span>${d.deviceCenters}</span>
    <span style="color:#fff;font-weight:bold;">Ablation centers</span><span>${d.ablationCenters}</span>
    <span style="color:#fff;font-weight:bold;">Visiting EP</span><span style="color:${visitColor};">${d.visitingEP}</span>
    <span style="color:#fff;font-weight:bold;">Last updated</span><span style="color:rgba(168,224,74,0.8);">${d.lastUpdated}</span>
  </div>`;
}

function buildAfricaResultsSVG(container, W, H) {
  const svg=d3.select(container).append('svg')
    .attr('viewBox',`0 0 ${W} ${H}`)
    .attr('preserveAspectRatio','xMidYMid meet')
    .style('display','block');
  svg.append('rect').attr('width',W).attr('height',H).attr('fill','#0d3b3e');
  const proj=d3.geoMercator().center([22,0]).scale(W*0.44).translate([W/2+10,H/2+20]);
  const path=d3.geoPath(proj);
  const africa=topojson.feature(worldData,worldData.objects.countries).features.filter(d=>!!getAN(+d.id));
  svg.selectAll('path').data(africa).join('path').attr('d',path).attr('stroke',CS).attr('stroke-width',0.5)
    .attr('fill',d=>countryEPData[getAN(+d.id)]?CC:'#c0392b')
    .style('cursor','pointer')
    .on('mousemove',(e,d)=>{const n=getAN(+d.id);tip(e,n,getCountryTip(n));})
    .on('mouseleave',untip);
  const lg=svg.append('g'),ll=svg.append('g');
  africa.forEach(d=>{
    const n=getAN(+d.id);if(!n)return;
    const c=path.centroid(d);if(!c||isNaN(c[0]))return;
    const area=path.area(d);const ext=extA[n];
    const disp=n.replace('Congo-Brazzaville','Congo-B').replace('DR Congo','DR Congo').replace('Central African Republic','Cent. African Rep.').replace('Western Sahara','W. Sahara').replace('Equatorial Guinea','Eq. Guinea');
    if(ext){const[lx,ly]=ext;lg.append('line').attr('x1',c[0]).attr('y1',c[1]).attr('x2',lx<W/2?lx+5:lx-5).attr('y2',ly).attr('stroke',CL).attr('stroke-width',0.7).attr('stroke-dasharray','2,2');ll.append('text').attr('x',lx<W/2?lx-2:lx+2).attr('y',ly+3).attr('text-anchor',lx<W/2?'end':'start').attr('font-size',Math.min(W*0.0077,9)+'px').attr('font-family','DM Sans,sans-serif').attr('fill','#c8d8dc').attr('font-weight','500').text(disp);}
    else{if(area<70*(W/520)**2)return;const fs=Math.min(area>3000*(W/520)**2?W*0.0094:area>800*(W/520)**2?W*0.0077:W*0.0068,area>3000*(W/520)**2?13:area>800*(W/520)**2?11:9);const words=disp.split(' ');if(words.length>=3&&area>1200*(W/520)**2){const mid=Math.ceil(words.length/2);[[words.slice(0,mid).join(' '),-4],[words.slice(mid).join(' '),8]].forEach(([t,dy])=>{ll.append('text').attr('x',c[0]).attr('y',c[1]+dy).attr('text-anchor','middle').attr('font-size',fs+'px').attr('font-family','DM Sans,sans-serif').attr('fill','#fff').attr('font-weight','500').attr('paint-order','stroke').attr('stroke','rgba(0,0,0,0.65)').attr('stroke-width','2px').text(t);})}else{ll.append('text').attr('x',c[0]).attr('y',c[1]+2).attr('text-anchor','middle').attr('font-size',fs+'px').attr('font-family','DM Sans,sans-serif').attr('fill','#fff').attr('font-weight','500').attr('paint-order','stroke').attr('stroke','rgba(0,0,0,0.65)').attr('stroke-width','2px').text(disp);}}
  });
  const ig=svg.append('g');
  africaIslands.forEach(isl=>{
    const[px,py]=proj([isl.lon,isl.lat]);const col='#c0392b';const lx=px+isl.dx*(W/520)*2,ly=py+isl.dy*(H/620)*1.4;
    ig.append('circle').attr('cx',px).attr('cy',py).attr('r',W>600?5:3.5).attr('fill',col).attr('stroke','rgba(255,255,255,0.35)').attr('stroke-width',0.8).style('cursor','pointer').on('mousemove',e=>tip(e,isl.name,'Data Not Yet Available')).on('mouseleave',untip);
    ig.append('line').attr('x1',px).attr('y1',py).attr('x2',lx).attr('y2',ly).attr('stroke',CL).attr('stroke-width',0.6).attr('stroke-dasharray','2,2');
    ig.append('text').attr('x',lx+(isl.anchor==='start'?2:-2)).attr('y',ly+3).attr('text-anchor',isl.anchor).attr('font-size',Math.min(W*0.0077,9)+'px').attr('font-family','DM Sans,sans-serif').attr('fill','#c8d8dc').attr('font-weight','500').text(isl.name);
  });
  return svg;
}

function buildSEAResultsSVG(container, W, H) {
  const svg=d3.select(container).append('svg')
    .attr('viewBox',`0 0 ${W} ${H}`)
    .attr('preserveAspectRatio','xMidYMid meet')
    .style('display','block');
  svg.append('rect').attr('width',W).attr('height',H).attr('fill','#0d3b3e');
  const seaCountries=['Cambodia','Laos','Myanmar','Thailand','Vietnam'];
  const proj=d3.geoMercator().center([103,17]).scale(W*0.85).translate([W/2,H*0.62]);
  const path=d3.geoPath(proj);
  const sea=topojson.feature(worldData,worldData.objects.countries).features.filter(d=>{const n=getSN(+d.id);return n&&seaCountries.includes(n);});
  svg.selectAll('path.sea').data(sea).join('path').attr('class','sea').attr('d',path)
    .attr('stroke',CS).attr('stroke-width',0.5)
    .attr('fill', d => countryEPData[getSN(+d.id)] ? CC : '#c0392b')
    .style('cursor','pointer')
    .on('mousemove',(e,d)=>{const n=getSN(+d.id);tip(e,n,getCountryTip(n));})
    .on('mouseleave',untip);
  const ll=svg.append('g');
  sea.forEach(d=>{const n=getSN(+d.id);if(!n)return;const c=path.centroid(d);if(!c||isNaN(c[0]))return;const area=path.area(d);if(area<80)return;const fs=Math.min(area>8000?W*0.024:area>2000?W*0.021:W*0.018, area>8000?14:area>2000?12:10);ll.append('text').attr('x',c[0]).attr('y',c[1]+2).attr('text-anchor','middle').attr('font-size',fs+'px').attr('font-family','DM Sans,sans-serif').attr('fill','#fff').attr('font-weight','500').attr('paint-order','stroke').attr('stroke','rgba(0,0,0,0.65)').attr('stroke-width','2.5px').text(n);});
  // Mongolia inset
  const mW=W*0.38,mH=H*0.18,mX=W*0.58,mY=H*0.04;
  svg.append('rect').attr('x',mX-8).attr('y',mY-8).attr('width',mW+16).attr('height',mH+16).attr('rx',8).attr('fill','rgba(13,59,62,0.85)').attr('stroke','rgba(168,224,74,0.2)').attr('stroke-width',1);
  const mongFeature=topojson.feature(worldData,worldData.objects.countries).features.find(d=>+d.id===496);
  if(mongFeature){
    const mongProj=d3.geoMercator().fitExtent([[mX,mY],[mX+mW,mY+mH]],mongFeature);
    const mongPath=d3.geoPath(mongProj);
    svg.append('path').datum(mongFeature).attr('d',mongPath).attr('fill',CC).attr('stroke',CS).attr('stroke-width',0.5).style('cursor','pointer').on('mousemove',e=>tip(e,'Mongolia',getCountryTip('Mongolia'))).on('mouseleave',untip);
    const mc=mongPath.centroid(mongFeature);
    svg.append('text').attr('x',mc[0]).attr('y',mc[1]+2).attr('text-anchor','middle').attr('font-size',W>600?'11px':'8px').attr('font-family','DM Sans,sans-serif').attr('fill','#fff').attr('font-weight','500').attr('paint-order','stroke').attr('stroke','rgba(0,0,0,0.65)').attr('stroke-width','2px').text('Mongolia');
  }
  svg.append('text').attr('x',mX-4).attr('y',mY-14).attr('font-size','9px').attr('font-family','DM Sans,sans-serif').attr('fill','rgba(255,255,255,0.35)').attr('font-weight','600').attr('letter-spacing','0.08em').text('INSET');
  return svg;
}

function openResultsModal(type) {
  const modal=document.getElementById('results-modal');
  const body=document.getElementById('results-modal-body');
  body.innerHTML='';
  modal.classList.add('open');
  document.body.style.overflow='hidden';
  if(type==='africa'){
    document.getElementById('results-modal-title').textContent='Africa — Survey Results';
    document.getElementById('results-modal-meta').textContent='31 countries surveyed';
  }else{
    document.getElementById('results-modal-title').textContent='Southeast Asia & Mongolia — Survey Results';
    document.getElementById('results-modal-meta').textContent='2 countries surveyed';
  }
  requestAnimationFrame(()=>requestAnimationFrame(()=>{
    const W=body.clientWidth||window.innerWidth;
    const H=body.clientHeight||(window.innerHeight-115);
    const svgSel=type==='africa'?buildAfricaResultsSVG(body,W,H):buildSEAResultsSVG(body,W,H);
    svgSel.style('width',W+'px').style('height',H+'px').style('position','absolute').style('top','0').style('left','0');
    const svgEl=svgSel.node();
    const zoomG=document.createElementNS('http://www.w3.org/2000/svg','g');
    zoomG.setAttribute('class','zoom-g');
    while(svgEl.firstChild) zoomG.appendChild(svgEl.firstChild);
    svgEl.appendChild(zoomG);
    const zoom=d3.zoom().scaleExtent([0.8,8])
      .on('start',()=>body.classList.add('panning'))
      .on('end',()=>body.classList.remove('panning'))
      .on('zoom',(event)=>{d3.select(zoomG).attr('transform',event.transform);});
    svgSel.call(zoom);
    const initScale=0.85;
    svgSel.call(zoom.transform,d3.zoomIdentity.translate(W*(1-initScale)/2,H*(1-initScale)/2).scale(initScale));
  }));
}
function closeResultsModal(){
  document.getElementById('results-modal').classList.remove('open');
  document.body.style.overflow='';
  untip();
}
document.getElementById('results-modal').addEventListener('keydown',e=>{if(e.key==='Escape')closeResultsModal();});
document.addEventListener('keydown',e=>{if(e.key==='Escape'&&document.getElementById('results-modal').classList.contains('open'))closeResultsModal();});

