function openLightbox(img) {
  const lb = document.getElementById('lightbox');
  const lbImg = document.getElementById('lightbox-img');
  lbImg.src = img.src;
  lb.style.display = 'block';

  // Reset transform state
  let scale = 1, tx = 0, ty = 0;
  let dragging = false, startX = 0, startY = 0, startTx = 0, startTy = 0;

  function applyTransform() {
    lbImg.style.transform = `translate(${tx}px,${ty}px) scale(${scale})`;
  }

  // Wait for image to load then center it
  lbImg.onload = function() {
    const vw = window.innerWidth, vh = window.innerHeight;
    const iw = lbImg.naturalWidth, ih = lbImg.naturalHeight;
    const fitScale = Math.min(vw * 0.95 / iw, vh * 0.95 / ih);
    scale = fitScale;
    tx = (vw - iw * fitScale) / 2;
    ty = (vh - ih * fitScale) / 2;
    lbImg.style.transformOrigin = '0 0';
    applyTransform();
  };
  if (lbImg.complete && lbImg.naturalWidth) lbImg.onload();

  // Scroll to zoom
  lb._wheel = function(e) {
    e.preventDefault();
    const rect = lbImg.getBoundingClientRect();
    const mouseX = e.clientX, mouseY = e.clientY;
    const delta = e.deltaY > 0 ? 0.85 : 1.18;
    const newScale = Math.min(Math.max(scale * delta, 0.3), 10);
    // Zoom toward mouse position
    tx = mouseX - (mouseX - tx) * (newScale / scale);
    ty = mouseY - (mouseY - ty) * (newScale / scale);
    scale = newScale;
    applyTransform();
  };
  lb.addEventListener('wheel', lb._wheel, {passive: false});

  // Drag to pan
  lb._mousedown = function(e) {
    if (e.target === lbImg || e.target === lb || e.target.id === 'lightbox-inner') {
      dragging = true;
      startX = e.clientX; startY = e.clientY;
      startTx = tx; startTy = ty;
      lb.style.cursor = 'grabbing';
    }
  };
  lb._mousemove = function(e) {
    if (!dragging) return;
    tx = startTx + (e.clientX - startX);
    ty = startTy + (e.clientY - startY);
    applyTransform();
  };
  lb._mouseup = function() { dragging = false; lb.style.cursor = 'grab'; };
  lb.addEventListener('mousedown', lb._mousedown);
  window.addEventListener('mousemove', lb._mousemove);
  window.addEventListener('mouseup', lb._mouseup);
  lb.style.cursor = 'grab';

  // Touch pinch-zoom
  let lastDist = 0;
  lb._touchstart = function(e) {
    if (e.touches.length === 2) {
      lastDist = Math.hypot(e.touches[0].clientX - e.touches[1].clientX, e.touches[0].clientY - e.touches[1].clientY);
    } else if (e.touches.length === 1) {
      dragging = true;
      startX = e.touches[0].clientX; startY = e.touches[0].clientY;
      startTx = tx; startTy = ty;
    }
  };
  lb._touchmove = function(e) {
    e.preventDefault();
    if (e.touches.length === 2) {
      const dist = Math.hypot(e.touches[0].clientX - e.touches[1].clientX, e.touches[0].clientY - e.touches[1].clientY);
      const delta = dist / lastDist;
      scale = Math.min(Math.max(scale * delta, 0.3), 10);
      lastDist = dist;
      applyTransform();
    } else if (e.touches.length === 1 && dragging) {
      tx = startTx + (e.touches[0].clientX - startX);
      ty = startTy + (e.touches[0].clientY - startY);
      applyTransform();
    }
  };
  lb._touchend = function() { dragging = false; };
  lb.addEventListener('touchstart', lb._touchstart, {passive:true});
  lb.addEventListener('touchmove', lb._touchmove, {passive:false});
  lb.addEventListener('touchend', lb._touchend);

  // ESC to close
  lb._keydown = function(e) { if (e.key === 'Escape') closeLightbox(); };
  document.addEventListener('keydown', lb._keydown);
}

function closeLightbox() {
  const lb = document.getElementById('lightbox');
  lb.style.display = 'none';
  // Clean up event listeners
  if (lb._wheel) lb.removeEventListener('wheel', lb._wheel);
  if (lb._mousedown) lb.removeEventListener('mousedown', lb._mousedown);
  if (lb._mousemove) window.removeEventListener('mousemove', lb._mousemove);
  if (lb._mouseup) window.removeEventListener('mouseup', lb._mouseup);
  if (lb._touchstart) lb.removeEventListener('touchstart', lb._touchstart);
  if (lb._touchmove) lb.removeEventListener('touchmove', lb._touchmove);
  if (lb._touchend) lb.removeEventListener('touchend', lb._touchend);
  if (lb._keydown) document.removeEventListener('keydown', lb._keydown);
}

